		googletag.defineSlot('/1021319/tf_new-right-gutter', [[300, 600], [160, 600]], 'div-gpt-ad-1615539722021-0').defineSizeMapping(adsRailMapping).setCollapseEmptyDiv(true,true).addService(googletag.pubads());
				//googletag.defineSlot('/1021319/Next_Millennium_1x1', [1, 1], 'div-gpt-ad-1561383187188-0').addService(googletag.pubads());
